<?php
declare(strict_types=1);
require dirname(__DIR__).'/control-escaneres/bootstrap.php';require_once dirname(__DIR__,2).'/config/config.php';
use App\Auth\{AuthenticatedUser,OrganizationalAccess};use App\Core\Database;use App\Repositories\OrganizationalAccessRepository;use App\Services\ModuleNavigationBuilder;
$pdo=Database::getConnection();
test('cinco tablas organizacionales aplicadas',fn()=>same(5,(int)$pdo->query("SELECT COUNT(*) FROM information_schema.tables WHERE table_schema=DATABASE() AND table_name IN('areas_organizacionales','usuario_areas','modulos','area_modulos','usuario_modulos')")->fetchColumn()));
test('columna organizacional nullable y separada',fn()=>same(1,(int)$pdo->query("SELECT COUNT(*) FROM information_schema.columns WHERE table_schema=DATABASE() AND table_name='scanners' AND column_name='area_organizacional_id' AND is_nullable='YES'")->fetchColumn()));
test('cuatro áreas exactas',fn()=>same(['administracion','calidad','embarques','sistemas'],$pdo->query('SELECT clave FROM areas_organizacionales ORDER BY clave')->fetchAll(PDO::FETCH_COLUMN)));
test('ocho módulos exactos',fn()=>same(8,(int)$pdo->query('SELECT COUNT(*) FROM modulos')->fetchColumn()));
test('doce asociaciones iniciales',fn()=>same(12,(int)$pdo->query('SELECT COUNT(*) FROM area_modulos WHERE activo=1')->fetchColumn()));
test('asociaciones coinciden con política aprobada',function()use($pdo){$rows=$pdo->query("SELECT a.clave,GROUP_CONCAT(m.clave ORDER BY m.orden) modules FROM areas_organizacionales a JOIN area_modulos am ON am.area_id=a.id AND am.activo=1 JOIN modulos m ON m.id=am.modulo_id GROUP BY a.id ORDER BY a.clave")->fetchAll(PDO::FETCH_KEY_PAIR);same(['administracion'=>'dashboard,reportes,administracion,configuracion_general','calidad'=>'dashboard','embarques'=>'dashboard,ferrocheck,inventario_patio,reportes','sistemas'=>'dashboard,control_escaneres,configuracion_general'],$rows);});
test('nueve permisos nuevos',fn()=>same(9,(int)$pdo->query("SELECT COUNT(*) FROM permisos WHERE clave LIKE 'areas.%' OR clave LIKE 'modulos.%'")->fetchColumn()));
test('Administrador recibe nueve permisos',fn()=>same(9,(int)$pdo->query("SELECT COUNT(*) FROM rol_permisos rp JOIN roles r ON r.id=rp.rol_id JOIN permisos p ON p.id=rp.permiso_id WHERE r.nombre='Administrador' AND (p.clave LIKE 'areas.%' OR p.clave LIKE 'modulos.%')")->fetchColumn()));
$row=$pdo->query("SELECT u.id,u.nombre,u.usuario FROM usuarios u WHERE u.usuario='azarel' AND u.activo=1")->fetch(PDO::FETCH_ASSOC);$permissions=$pdo->query("SELECT DISTINCT p.clave FROM permisos p JOIN rol_permisos rp ON rp.permiso_id=p.id JOIN usuario_roles ur ON ur.rol_id=rp.rol_id WHERE ur.usuario_id=".(int)$row['id'])->fetchAll(PDO::FETCH_COLUMN);$user=new AuthenticatedUser((int)$row['id'],$row['nombre'],$row['usuario'],['Administrador'],$permissions);$access=new OrganizationalAccess($user,new OrganizationalAccessRepository($pdo));
test('azarel conserva Sistemas como principal',fn()=>same(1,(int)$pdo->query("SELECT COUNT(*) FROM usuario_areas ua JOIN areas_organizacionales a ON a.id=ua.area_id WHERE ua.usuario_id=".(int)$row['id']." AND a.clave='sistemas' AND ua.activo=1 AND ua.es_principal=1")->fetchColumn()));
test('azarel tiene alcance global efectivo',fn()=>ok($user->can('areas.acceso_global')&&$user->can('modulos.acceso_global')));
test('azarel ve los ocho módulos activos',fn()=>same(8,count($access->authorizedModules())));
test('sidebar de azarel conserva orden del catálogo',function()use($access){$nav=(new ModuleNavigationBuilder($access))->build('/Ferrocheck/public');same(['dashboard','ferrocheck','inventario_material','inventario_patio','control_escaneres','reportes','administracion','configuracion_general'],array_column($nav,'key'));});
test('ningún escáner fue asignado automáticamente',fn()=>same(0,(int)$pdo->query('SELECT COUNT(*) FROM scanners WHERE area_organizacional_id IS NOT NULL')->fetchColumn()));
test('migración registrada',fn()=>same(1,(int)$pdo->query("SELECT COUNT(*) FROM schema_migrations WHERE module='organizational-access' AND migration_name='20260722_013_prepare_organizational_access.sql'")->fetchColumn()));
$layout=file_get_contents(dirname(__DIR__,2).'/app/Views/admin/_layout.php');$form=file_get_contents(dirname(__DIR__,2).'/app/Views/admin/_user-form.php');$front=file_get_contents(dirname(__DIR__,2).'/public/index.php');$scannerEdit=file_get_contents(dirname(__DIR__,2).'/app/Views/control-escaneres/editar.php');
test('Administración expone navegación secundaria protegida',fn()=>ok(str_contains($layout,"areas.ver")&&str_contains($layout,"modulos.ver")&&str_contains($layout,"seccion=areas")&&str_contains($layout,"seccion=modulos")));
test('formulario separa área principal, adicionales y excepciones',fn()=>ok(str_contains($form,'name="principal_area_id"')&&str_contains($form,'obligatoria si el usuario está activo')&&str_contains($form,'name="area_ids[]"')&&str_contains($form,'module_decision')&&str_contains($form,'Heredar de áreas')&&str_contains($form,'Denegar individualmente')));
test('backend protege Administración y Control de Escáneres por módulo',fn()=>ok(str_contains($front,"requireModuleAccess('administracion')")&&str_contains($front,"requireModuleAccess('control_escaneres','escaneres.ver')")));
test('FerroCheck permanece en transición sin guarda definitiva',fn()=>ok(!str_contains($front,"requireModuleAccess('ferrocheck')")));
test('escáner distingue área propietaria y operativa',fn()=>ok(str_contains($scannerEdit,'Área organizacional propietaria')&&str_contains($scannerEdit,'No sustituye el área operativa habitual')));
finish('Organizational Applied');
